const ins = $json.data || [];
const campaign = $node['Split Campaigns'].json;
let flagged = [];
let winners = [];
let anomalies = [];
const spendEfficencyTier = campaign.spend_efficiency_tier || 'scaling';
const targetCpl = campaign.target_cpl || 50;
const targetRoas = campaign.target_roas || 2.0;
for (const ad of ins) {
  const spend = parseFloat(ad.spend || 0);
  const clicks = parseInt(ad.clicks || 0);
  const impressions = parseInt(ad.impressions || 0);
  const leads = (ad.actions || []).find(a => a.action_type === 'lead')?.value || 0;
  const purch = (ad.actions || []).find(a => a.action_type === 'purchase')?.value || 0;
  const rev = (ad.action_values || []).find(a => a.action_type === 'purchase')?.value || 0;
  const cpl = leads > 0 ? spend / parseInt(leads) : null;
  const roas = spend > 0 ? parseFloat(rev) / spend : 0;
  const freq = parseFloat(ad.frequency || 0);
  const ctr = parseFloat(ad.ctr || 0);
  const isCreativeFatigue = freq > 3.5 || (impressions > 50000 && ctr < 0.5);
  const isBudgetIneff = (cpl !== null && cpl > targetCpl * 1.5) || (roas > 0 && roas < targetRoas * 0.67);
  const isUnderperformer = isBudgetIneff || isCreativeFatigue;
  const isWinner = (roas > targetRoas * 1.5 || (cpl !== null && cpl < targetCpl * 0.6)) && spend > 20;
  const row = {
    ad_id: ad.ad_id,
    spend: Math.round(spend * 100) / 100,
    cpl: cpl ? Math.round(cpl * 100) / 100 : null,
    roas: Math.round(roas * 100) / 100,
    freq: Math.round(freq * 100) / 100,
    ctr: Math.round(ctr * 1000) / 10,
    leads: parseInt(leads),
    purchases: parseInt(purch),
    revenue: Math.round(parseFloat(rev) * 100) / 100,
    impressions,
    root_cause: isCreativeFatigue ? 'creative_fatigue' : (isBudgetIneff ? 'budget_inefficiency' : null)
  };
  if (isUnderperformer) flagged.push(row);
  else if (isWinner) winners.push(row);
  if ((freq > 4 && impressions > 100000) || (ctr < 0.3 && impressions > 100000)) anomalies.push({...row, anomaly_type: 'high_freq_low_ctr'});
}
return [{ json: {
  campaign_id: campaign.campaign_id,
  campaign_name: campaign.campaign_name,
  client_id: campaign.client_id,
  spend_efficiency_tier: spendEfficencyTier,
  flagged: flagged.sort((a,b) => b.spend - a.spend).slice(0, 10),
  winners: winners.sort((a,b) => b.roas - a.roas),
  anomalies,
  total_ads: ins.length,
  active_ads: ins.filter(a => parseFloat(a.spend || 0) > 0).length
} }];

